import React, { useEffect, useContext } from "react";
import { Footer } from "./Footer";
import { useDispatch } from "react-redux";
import { Link } from "react-router-dom";
import { Navbar } from "./Navbar";
import { getCartItems } from "./actions/user_actions";
import CartContext from "./context/CartContext";
import { useHistory } from "react-router";
import { CartBlock } from "./CartBlock";

export const CartPage = (props) => {
  // const dispatch = useDispatch();
  // useEffect(() => {
  //     let cartItems =[]
  //     if (props.user && props.user.cart) {
  //         if (props.user.cart.length > 0) {
  //             props.user.forEach(item=>{
  //                 cartItems.push(item.id)
  //             });
  //             dispatch(getCartItems(cartItems,props.user.cart))
  //         }

  //     }
  // }, [props.user])
  const context = useContext(CartContext);
  const { carts, getcart } = context;
  let history = useHistory();

  useEffect(() => {
    if (localStorage.getItem("token")) {
      getcart();
    } else {
      history.push("/login");
    }
  }, []);
  return (
    <>
      <Navbar />
      <div className="cart-area pt-90 pb-90">
        <div className="container">
          <div className="row justify-content-center">
            <div className="col-xl-7">
              <div className="cart-wrapper">
                <div className="table-responsive">
                  <table className="table mb-0">
                    <thead>
                      <tr>
                        <th className="product-thumbnail"></th>
                        <th className="product-name">Product</th>
                        <th className="product-price">Price</th>
                        <th className="product-quantity">QUANTITY</th>
                        <th className="product-subtotal">SUBTOTAL</th>
                        <th className="product-delete"></th>
                      </tr>
                    </thead>
                    {carts.map((cart) => {
                      return <CartBlock products={props.user} cart={cart} />;
                    })}
                  </table>
                </div>
              </div>
              <div className="shop-cart-bottom">
                <div className="cart-coupon">
                  <form action="#">
                    <input type="text" placeholder="Enter Coupon Code..." />
                    <button className="btn">Apply Coupon</button>
                  </form>
                </div>
                <div className="continue-shopping">
                  <Link href="shop.html" className="btn">
                    Update Cart
                  </Link>
                </div>
              </div>
            </div>
            <div className="col-xl-5 col-lg-12">
              <div className="shop-cart-total">
                <h3 className="title">Cart Totals</h3>
                <div className="shop-cart-widget">
                  <form action="#">
                    <ul>
                      <li className="sub-total">
                        <span>Subtotal</span> ₹ 136.00
                      </li>
                      <li>
                        <span>Shipping</span>
                        <div className="shop-check-wrap">
                          <div className="custom-control custom-checkbox">
                            <input
                              type="checkbox"
                              className="custom-control-input"
                              id="customCheck1"
                            />
                            <label
                              className="custom-control-label"
                              htmlFor="customCheck1"
                            >
                              Free Shipping
                            </label>
                          </div>
                          <div className="custom-control custom-checkbox">
                            <input
                              type="checkbox"
                              className="custom-control-input"
                              id="customCheck2"
                            />
                            <label
                              className="custom-control-label"
                              htmlFor="customCheck2"
                            >
                              LOCAL PICKUP: ₹5.00
                            </label>
                          </div>
                        </div>
                      </li>
                      <li className="cart-total-amount">
                        <span>Total Price</span>{" "}
                        <span className="amount">₹ 151.00</span>
                      </li>
                    </ul>
                    <Link href="checkout.html" className="btn">
                      PROCEED TO CHECKOUT
                    </Link>
                  </form>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
      <Footer />
    </>
  );
};
